import types, sys

_module = types.ModuleType("leave_request_ui")


class _LeaveRequestFormController:
    """
    Minimal controller that the tests exercise.
    Swap for the real implementation.
    """

    MANDATORY_FIELDS = ["employee_id", "leave_type", "start_date", "end_date", "reason"]

    def __init__(self, leave_request_service, audit_service):
        self._svc = leave_request_service
        self._audit = audit_service

    # ------------------------------------------------------------------
    def submit(self, actor, form_data: dict) -> LeaveRequest:
        """
        Validate actor + form, delegate to service, write audit record.
        Returns the created LeaveRequest on success.
        """
        # Auth checks
        if not getattr(actor, "is_authenticated", False):
            raise AuthenticationError("User must be authenticated.")
        if getattr(actor, "role", None) != "MANAGER":
            raise AuthorizationError("Only managers may create leave requests.")

        # Field validation
        errors = {}
        for f in self.MANDATORY_FIELDS:
            value = form_data.get(f)
            if value is None or (isinstance(value, str) and not value.strip()):
                errors[f] = f"'{f}' is required."

        # Date sanity check
        start = form_data.get("start_date")
        end = form_data.get("end_date")
        if start and end and end < start:
            errors["end_date"] = "'end_date' must be on or after 'start_date'."

        if errors:
            raise ValidationError(errors)

        # Delegate to service
        lr = self._svc.create(
            LeaveRequest(
                employee_id=form_data["employee_id"],
                leave_type=form_data["leave_type"],
                start_date=form_data["start_date"],
                end_date=form_data["end_date"],
                reason=form_data["reason"],
                manager_id=actor.id,
            )
        )

        # Audit
        self._audit.write(
            AuditRecord(
                actor_id=actor.id,
                action="CREATE_LEAVE_REQUEST",
                resource="LeaveRequest",
                resource_id=lr.id,
                metadata={"employee_id": form_data["employee_id"]},
            )
        )
        return lr


_module.LeaveRequestFormController = _LeaveRequestFormController
sys.modules.setdefault("leave_request_ui", _module)


