        employee_id=form_data["employee_id"],
        leave_type=form_data["leave_type"],
        start_date=form_data["start_date"],
        end_date=form_data["end_date"],
        reason=form_data["reason"],
        manager_id=manager_id,
        status="PENDING",
    )
    return lr


