class TestMandatoryFieldValidation:
    """Each mandatory field, when missing or blank, must produce a ValidationError."""

    MANDATORY_FIELDS = ["employee_id", "leave_type", "start_date", "end_date", "reason"]

    @pytest.mark.parametrize("missing_field", MANDATORY_FIELDS)
    def test_missing_field_raises_validation_error(
        self, ui_form, manager_user, valid_form_data, missing_field
    ):
        """Omitting any mandatory field must raise ValidationError."""
        form_data = {**valid_form_data}
        del form_data[missing_field]

        with pytest.raises(ValidationError) as exc_info:
            ui_form.submit(manager_user, form_data)

        assert missing_field in exc_info.value.errors

    @pytest.mark.parametrize("blank_field", ["employee_id", "leave_type", "reason"])
    def test_blank_string_field_raises_validation_error(
        self, ui_form, manager_user, valid_form_data, blank_field
    ):
        """Whitespace-only strings must be treated as missing."""
        form_data = {**valid_form_data, blank_field: "   "}

        with pytest.raises(ValidationError) as exc_info:
            ui_form.submit(manager_user, form_data)

        assert blank_field in exc_info.value.errors

    @pytest.mark.parametrize("missing_field", MANDATORY_FIELDS)
    def test_missing_field_does_not_call_service(
        self, ui_form, leave_request_service, manager_user, valid_form_data, missing_field
    ):
        form_data = {**valid_form_data}
        del form_data[missing_field]

        with pytest.raises(ValidationError):
            ui_form.submit(manager_user, form_data)

        leave_request_service.create.assert_not_called()

    @pytest.mark.parametrize("missing_field", MANDATORY_FIELDS)
    def test_missing_field_does_not_write_audit(
        self, ui_form, audit_service, manager_user, valid_form_data, missing_field
    ):
        form_data = {**valid_form_data}
        del form_data[missing_field]

        with pytest.raises(ValidationError):
            ui_form.submit(manager_user, form_data)

        audit_service.write.assert_not_called()

    def test_multiple_missing_fields_reported_together(
        self, ui_form, manager_user
    ):
        """All missing-field errors should be aggregated in one exception."""
        with pytest.raises(ValidationError) as exc_info:
            ui_form.submit(manager_user, {})

        errors = exc_info.value.errors
        for f in self.MANDATORY_FIELDS:
            assert f in errors, f"Expected error for field '{f}' but got: {errors}"

    def test_end_date_before_start_date_raises_validation_error(
        self, ui_form, manager_user, valid_form_data
    ):
        form_data = {
            **valid_form_data,
            "start_date": date.today() + timedelta(days=10),
            "end_date": date.today() + timedelta(days=5),
        }
        with pytest.raises(ValidationError) as exc_info:
            ui_form.submit(manager_user, form_data)

        assert "end_date" in exc_info.value.errors

    def test_same_start_and_end_date_is_valid(
        self, ui_form, leave_request_service, manager_user, valid_form_data
    ):
        """A single-day leave request (start == end) should be accepted."""
