class TestSuccessfulCreation:
    """Happy-path: all fields present, manager authenticated."""

    def test_returns_leave_request_with_id(
        self, ui_form, leave_request_service, manager_user, valid_form_data
    ):
        expected = _make_created_leave_request(valid_form_data, manager_user.id, lr_id=42)
        leave_request_service.create.return_value = expected

        result = ui_form.submit(manager_user, valid_form_data)

        assert result.id == 42

    def test_service_called_once_with_correct_data(
        self, ui_form, leave_request_service, manager_user, valid_form_data
    ):
        leave_request_service.create.return_value = _make_created_leave_request(
            valid_form_data, manager_user.id
        )

        ui_form.submit(manager_user, valid_form_data)

        leave_request_service.create.assert_called_once()
        passed_lr: LeaveRequest = leave_request_service.create.call_args[0][0]
        assert passed_lr.employee_id == valid_form_data["employee_id"]
        assert passed_lr.leave_type == valid_form_data["leave_type"]
        assert passed_lr.start_date == valid_form_data["start_date"]
        assert passed_lr.end_date == valid_form_data["end_date"]
        assert passed_lr.reason == valid_form_data["reason"]
        assert passed_lr.manager_id == manager_user.id

    def test_leave_request_status_defaults_to_pending(
        self, ui_form, leave_request_service, manager_user, valid_form_data
    ):
        created = _make_created_leave_request(valid_form_data, manager_user.id)
        leave_request_service.create.return_value = created

        result = ui_form.submit(manager_user, valid_form_data)

        assert result.status == "PENDING"


