    def test_audit_not_written_when_service_raises(
        self, ui_form, leave_request_service, audit_service, manager_user, valid_form_data
    ):
        """If the service layer throws, no audit record should be persisted."""
        leave_request_service.create.side_effect = RuntimeError("DB error")

        with pytest.raises(RuntimeError):
            ui_form.submit(manager_user, valid_form_data)

        audit_service.write.assert_not_called()

    def test_audit_write_order_is_after_service_create(
        self, ui_form, leave_request_service, audit_service, manager_user, valid_form_data
    ):
        """
        Service creation must happen before the audit write
        (verified via call order on a shared mock manager).
        """
        call_order = []
        leave_request_service.create.side_effect = lambda *a, **kw: (
            call_order.append("create"),
            _make_created_leave_request(valid_form_data, manager_user.id),
